export default {
    name: 'TarjetaUsuario',
    props: {
        nombre: { type: String, required: true },
        email: String,
        avatar: { type: String, default: '/img/default.png' }
    },
    emits: ['click', 'eliminar'],
    setup(props, { emit }) {
        function handleClick() {
            emit('click', props.nombre)
        }
        return { handleClick }
    },
    template: `
        <div class="tarjeta" @click="handleClick">
            <img :src="avatar" :alt="nombre">
            <h3>{{ nombre }}</h3>
            <p>{{ email }}</p>
        </div>
    `
}
